/**
 * Determines whether a given host is on the private 192.168.0.0/16 local network.
 */
object NetworkUtils {

    private val LOCAL_SUBNET_PREFIX = "192.168."

    /**
     * Returns true only for RFC-1918 192.168.x.x addresses.
     * This is the *only* case where cleartext HTTP is permitted.
     */
    fun isLocalIoTAddress(host: String): Boolean {
        return host.startsWith(LOCAL_SUBNET_PREFIX) && isValidIPv4(host)
    }

    private fun isValidIPv4(host: String): Boolean {
        val parts = host.split(".")
        if (parts.size != 4) return false
        return parts.all { part ->
            val num = part.toIntOrNull() ?: return false
            num in 0..255
        }
    }

    /**
     * Validates that a URL uses an appropriate scheme for its destination.
     * - Local IoT devices (192.168.x.x): HTTP allowed
     * - Everything else (including cloud API): HTTPS required
     *
     * @throws SecurityException if the scheme/host combination is disallowed.
     */
    fun validateUrl(url: HttpUrl) {
        val host = url.host
        val scheme = url.scheme

        when {
            isLocalIoTAddress(host) -> {
                // HTTP is acceptable for local IoT devices that lack TLS support.
                // HTTPS is also fine if the device supports it.
                Log.d("NetworkUtils", "Local IoT device access: $scheme://$host")
            }
            scheme == "http" -> {
                throw SecurityException(
                    "Cleartext HTTP is not permitted for non-local host: $host. Use HTTPS."
                )
            }
            scheme == "https" -> {
                // Good — remote hosts must use HTTPS.
            }
            else -> {
                throw SecurityException("Unsupported scheme: $scheme")
            }
        }
    }
}

/**
 * OkHttp Interceptor that enforces transport security policy at the application layer.
 *
 * - Blocks cleartext HTTP to any host outside 192.168.0.0/16.
 * - Ensures cloud/remote endpoints always use HTTPS with proper TLS validation.
 */
class TransportSecurityInterceptor : Interceptor {

    @Throws(IOException::class)
    override fun intercept(chain: Interceptor.Chain): Response {
        val request = chain.request()
        val url = request.url

        try {
            NetworkUtils.validateUrl(url)
        } catch (e: SecurityException) {
            throw IOException("Transport security policy violation: ${e.message}", e)
        }

        return chain.proceed(request)
    }
}

/**
 * Interceptor that automatically upgrades HTTP → HTTPS for non-local hosts.
 * Acts as a safety net in case a caller accidentally constructs an HTTP URL
 * for a remote endpoint.
 */
class HttpsUpgradeInterceptor : Interceptor {

    @Throws(IOException::class)
    override fun intercept(chain: Interceptor.Chain): Response {
        val originalRequest = chain.request()
        val url = originalRequest.url

        // If it's already HTTPS or it's a local IoT device, pass through.
        if (url.scheme == "https" || NetworkUtils.isLocalIoTAddress(url.host)) {
            return chain.proceed(originalRequest)
        }

        // Upgrade to HTTPS for remote hosts.
        val secureUrl = url.newBuilder()
            .scheme("https")
            .build()

        Log.w(
            "HttpsUpgrade",
            "Upgraded cleartext request to HTTPS: ${url.host}"
        )

        val secureRequest = originalRequest.newBuilder()
            .url(secureUrl)
            .build()

        return chain.proceed(secureRequest)
    }
}

/**
 * Configuration for the IoT HTTP client.
