data class IoTClientConfig(
    val cloudBaseUrl: String = "https://api.example.com",
    val connectTimeoutSeconds: Long = 10,
    val readTimeoutSeconds: Long = 30,
    val writeTimeoutSeconds: Long = 30,
    val localDeviceTimeoutSeconds: Long = 5,
    val enableLogging: Boolean = false
)

/**
 * Sealed class representing the result of an API/device call.
 */
sealed class IoTResult<out T> {
    data class Success<T>(val data: T, val code: Int) : IoTResult<T>()
    data class Error(val message: String, val code: Int? = null, val exception: Throwable? = null) : IoTResult<Nothing>()
}

/**
 * HTTP client for communicating with both local IoT devices (HTTP on 192.168.x.x)
 * and the cloud API (HTTPS only).
 *
 * Security design:
 * - Cleartext HTTP is ONLY allowed for 192.168.0.0/16 addresses (local IoT devices).
 * - All remote/cloud traffic is forced to HTTPS with standard certificate validation.
 * - No custom TrustManagers, no certificate-validation bypasses.
 * - An application-layer interceptor enforces the policy even if Android's
 *   network_security_config is misconfigured.
 */
class IoTHttpClient(
    private val config: IoTClientConfig = IoTClientConfig()
) {

    companion object {
        private const val TAG = "IoTHttpClient"
        private val JSON_MEDIA_TYPE = "application/json; charset=utf-8".toMediaType()
    }

    /**
     * OkHttpClient for cloud (remote) endpoints — HTTPS only, standard TLS.
     */
    private val cloudClient: OkHttpClient by lazy { buildCloudClient() }

    /**
     * OkHttpClient for local IoT devices — shorter timeouts, HTTP permitted
     * only for 192.168.x.x hosts.
     */
    private val localClient: OkHttpClient by lazy { buildLocalClient() }

    // ----------------------------------------------------------------
    // Client builders
    // ----------------------------------------------------------------

    private fun buildCloudClient(): OkHttpClient {
        val builder = OkHttpClient.Builder()
            .connectTimeout(config.connectTimeoutSeconds, TimeUnit.SECONDS)
            .readTimeout(config.readTimeoutSeconds, TimeUnit.SECONDS)
            .writeTimeout(config.writeTimeoutSeconds, TimeUnit.SECONDS)
            // Safety net: upgrade any accidental HTTP to HTTPS
            .addInterceptor(HttpsUpgradeInterceptor())
            // Hard enforcement: block cleartext to non-local hosts
            .addInterceptor(TransportSecurityInterceptor())
            // Use the platform default TLS configuration (system trust store).
            .applyDefaultTls()

        if (config.enableLogging) {
            builder.addInterceptor(
                HttpLoggingInterceptor().apply {
                    level = HttpLoggingInterceptor.Level.BODY
                }
            )
        }

        return builder.build()
    }

    private fun buildLocalClient(): OkHttpClient {
        val builder = OkHttpClient.Builder()
            .connectTimeout(config.localDeviceTimeoutSeconds, TimeUnit.SECONDS)
            .readTimeout(config.localDeviceTimeoutSeconds, TimeUnit.SECONDS)
            .writeTimeout(config.localDeviceTimeoutSeconds, TimeUnit.SECONDS)
            // Enforce: only 192.168.x.x may use cleartext
            .addInterceptor(TransportSecurityInterceptor())

        if (config.enableLogging) {
            builder.addInterceptor(
                HttpLoggingInterceptor().apply {
                    level = HttpLoggingInterceptor.Level.BODY
                }
            )
        }

        return builder.build()
    }

    /**
     * Applies the platform-default TLS settings explicitly.
     * We do NOT install a custom or permissive TrustManager.
     */
    private fun OkHttpClient.Builder.applyDefaultTls(): OkHttpClient.Builder {
        val trustManagerFactory = TrustManagerFactory.getInstance(
            TrustManagerFactory.getDefaultAlgorithm()
        )
        trustManagerFactory.init(null as KeyStore?)

        val trustManagers = trustManagerFactory.trustManagers
        val x509TrustManager = trustManagers.first { it is X509TrustManager } as X509TrustManager

        val sslContext = SSLContext.getInstance("TLS")
        sslContext.init(null, arrayOf(x509TrustManager), null)

        return this
            .sslSocketFactory(sslContext.socketFactory, x509TrustManager)
    }

    // ----------------------------------------------------------------
    // Client selection
    // ----------------------------------------------------------------

    /**
     * Selects the appropriate OkHttpClient based on the target host.
     */
    private fun clientForHost(host: String): OkHttpClient {
        return if (NetworkUtils.isLocalIoTAddress(host)) localClient else cloudClient
    }

    private fun clientForUrl(url: String): OkHttpClient {
        val parsed = HttpUrl.parse(url)
            ?: throw IllegalArgumentException("Invalid URL: $url")
        return clientForHost(parsed.host())
    }

    // ----------------------------------------------------------------
    // Public API — Cloud
    // ----------------------------------------------------------------

    /**
     * Performs a GET request to the cloud API.
     * Always uses HTTPS.
     *
     * @param path API path (e.g., "/v1/devices")
     * @param headers Optional additional headers
     * @param authToken Optional Bearer token
     */
    fun cloudGet(
        path: String,
        headers: Map<String, String> = emptyMap(),
        authToken: String? = null,
        callback: (IoTResult<String>) -> Unit
    ) {
        val url = "${config.cloudBaseUrl}${path}"
        require(url.startsWith("https://")) {
            "Cloud API URL must use HTTPS: $url"
        }
        get(url, headers, authToken, callback)
    }

    /**
