     * Always uses HTTPS.
     */
    fun cloudPost(
        path: String,
        jsonBody: String,
        headers: Map<String, String> = emptyMap(),
        authToken: String? = null,
        callback: (IoTResult<String>) -> Unit
    ) {
        val url = "${config.cloudBaseUrl}${path}"
        require(url.startsWith("https://")) {
            "Cloud API URL must use HTTPS: $url"
        }
        post(url, jsonBody, headers, authToken, callback)
    }

    /**
     * Performs a PUT request to the cloud API.
     * Always uses HTTPS.
     */
    fun cloudPut(
        path: String,
        jsonBody: String,
        headers: Map<String, String> = emptyMap(),
        authToken: String? = null,
        callback: (IoTResult<String>) -> Unit
    ) {
        val url = "${config.cloudBaseUrl}${path}"
        require(url.startsWith("https://")) {
            "Cloud API URL must use HTTPS: $url"
        }
        put(url, jsonBody, headers, authToken, callback)
    }

    /**
     * Performs a DELETE request to the cloud API.
     * Always uses HTTPS.
     */
    fun cloudDelete(
        path: String,
        headers: Map<String, String> = emptyMap(),
        authToken: String? = null,
        callback: (IoTResult<String>) -> Unit
    ) {
        val url = "${config.cloudBaseUrl}${path}"
        require(url.startsWith("https://")) {
            "Cloud API URL must use HTTPS: $url"
        }
        delete(url, headers, authToken, callback)
    }

    // ----------------------------------------------------------------
    // Public API — Local IoT Devices
    // ----------------------------------------------------------------

    /**
     * Sends a GET request to a local IoT device.
     * HTTP is permitted only for 192.168.x.x addresses.
     *
     * @param deviceIp The device IP (must be 192.168.x.x)
     * @param port The device port (default 80)
     * @param path The request path
     */
    fun deviceGet(
        deviceIp: String,
        port: Int = 80,
        path: String = "/",
        headers: Map<String, String> = emptyMap(),
        callback: (IoTResult<String>) -> Unit
    ) {
        requireLocalDevice(deviceIp)
        val url = "http://$deviceIp:$port$path"
        get(url, headers, authToken = null, callback = callback)
    }

    /**
     * Sends a POST request to a local IoT device.
     */
    fun devicePost(
        deviceIp: String,
        port: Int = 80,
        path: String = "/",
        jsonBody: String,
        headers: Map<String, String> = emptyMap(),
        callback: (IoTResult<String>) -> Unit
    ) {
        requireLocalDevice(deviceIp)
        val url = "http://$deviceIp:$port$path"
        post(url, jsonBody, headers, authToken = null, callback = callback)
    }

