    fun discoverDevice(
        deviceIp: String,
        port: Int = 80,
        statusPath: String = "/status",
        callback: (IoTResult<String>) -> Unit
    ) {
        requireLocalDevice(deviceIp)
        val url = "http://$deviceIp:$port$statusPath"
        get(url, emptyMap(), authToken = null, callback = callback)
    }

    // ----------------------------------------------------------------
    // Internal HTTP methods
    // ----------------------------------------------------------------

    private fun get(
        url: String,
        headers: Map<String, String>,
        authToken: String?,
        callback: (IoTResult<String>) -> Unit
    ) {
        val requestBuilder = Request.Builder().url(url).get()
        applyHeaders(requestBuilder, headers, authToken)
        execute(url, requestBuilder.build(), callback)
    }

    private fun post(
        url: String,
        jsonBody: String,
        headers: Map<String, String>,
        authToken: String?,
        callback: (IoTResult<String>) -> Unit
    ) {
        val body = jsonBody.toRequestBody(JSON_MEDIA_TYPE)
        val requestBuilder = Request.Builder().url(url).post(body)
        applyHeaders(requestBuilder, headers, authToken)
        execute(url, requestBuilder.build(), callback)
    }

    private fun put(
        url: String,
        jsonBody: String,
        headers: Map<String, String>,
        authToken: String?,
        callback: (IoTResult<String>) -> Unit
    ) {
        val body = jsonBody.toRequestBody(JSON_MEDIA_TYPE)
        val requestBuilder = Request.Builder().url(url).put(body)
        applyHeaders(requestBuilder, headers, authToken)
        execute(url, requestBuilder.build(), callback)
    }

    private fun delete(
        url: String,
        headers: Map<String, String>,
        authToken: String?,
        callback: (IoTResult<String>) -> Unit
    ) {
        val requestBuilder = Request.Builder().url(url).delete()
        applyHeaders(requestBuilder, headers, authToken)
        execute(url, requestBuilder.build(), callback)
    }

    private fun applyHeaders(
        builder: Request.Builder,
        headers: Map<String, String>,
        authToken: String?
    ) {
        headers.forEach { (key, value) -> builder.addHeader(key, value) }
        authToken?.let { token ->
            builder.addHeader("Authorization", "Bearer $token")
        }
    }

    private fun execute(
        url: String,
        request: Request,
        callback: (IoTResult<String>) -> Unit
    ) {
        val client = clientForUrl(url)

        client.newCall(request).enqueue(object : Callback {
            override fun onFailure(call: Call, e: IOException) {
                Log.e(TAG, "Request failed: ${request.url}", e)
                callback(
                    IoTResult.Error(
                        message = e.message ?: "Unknown network error",
                        exception = e
                    )
                )
            }

            override fun onResponse(call: Call, response: Response) {
                response.use { resp ->
                    val body = resp.body?.string()
                    if (resp.isSuccessful) {
                        callback(
                            IoTResult.Success(
                                data = body ?: "",
                                code = resp.code
                            )
                        )
                    } else {
                        Log.w(TAG, "HTTP ${resp.code} from ${request.url}: $body")
                        callback(
                            IoTResult.Error(
                                message = body ?: "HTTP ${resp.code}",
                                code = resp.code
                            )
                        )
                    }
                }
            }
        })
    }

    // ----------------------------------------------------------------
    // Synchronous variants (for use in coroutines / background threads)
    // ----------------------------------------------------------------

    /**
     * Synchronous GET — blocks the calling thread.
     * Use from a coroutine dispatcher or background thread only.
     */
    @Throws(IOException::class)
    fun cloudGetSync(
        path: String,
        headers: Map<String, String> = emptyMap(),
        authToken: String? = null
    ): IoTResult<String> {
        val url = "${config.cloudBaseUrl}${path}"
        require(url.startsWith("https://")) {
            "Cloud API URL must use HTTPS: $url"
        }
        return executeSync(url, headers, authToken) { builder ->
            builder.get()
        }
    }

    @Throws(IOException::class)
    fun deviceGetSync(
        deviceIp: String,
        port: Int = 80,
        path: String = "/",
        headers: Map<String, String> = emptyMap()
    ): IoTResult<String> {
        requireLocalDevice(deviceIp)
        val url = "http://$deviceIp:$port$path"
        return executeSync(url, headers, authToken = null) { builder ->
            builder.get()
        }
    }

    private fun executeSync(
        url: String,
        headers: Map<String, String>,
        authToken: String?,
        configure: (Request.Builder) -> Request.Builder
    ): IoTResult<String> {
        val requestBuilder = Request.Builder().url(url)
        applyHeaders(requestBuilder, headers, authToken)
        configure(requestBuilder)

        val client = clientForUrl(url)
        return try {
            val response = client.newCall(requestBuilder.build()).execute()
            response.use { resp ->
                val body = resp.body?.string()
                if (resp.isSuccessful) {
                    IoTResult.Success(data = body ?: "", code = resp.code)
                } else {
                    IoTResult.Error(message = body ?: "HTTP ${resp.code}", code = resp.code)
                }
            }
        } catch (e: IOException) {
            IoTResult.Error(message = e.message ?: "Network error", exception = e)
        }
    }

    // ----------------------------------------------------------------
    // Validation helpers
    // ----------------------------------------------------------------

    private fun requireLocalDevice(deviceIp: String) {
        require(NetworkUtils.isLocalIoTAddress(deviceIp)) {
            "Device IP must be a local 192.168.x.x address, got: $deviceIp"
        }
    }

    /**
     * Shuts down the connection pools and dispatcher threads.
     */
    fun shutdown() {
        cloudClient.dispatcher.executorService.shutdown()
        cloudClient.connectionPool.evictAll()
        localClient.dispatcher.executorService.shutdown()
        localClient.connectionPool.evictAll()
    }
}

